// Imperativo (vanilla JS)
document.getElementById('btn').textContent = 'Clicado!';
document.getElementById('btn').classList.add('active');

// Declarativo (React)
function Botao({ clicado }) {
  return (
    <button className={clicado ? 'active' : ''}>
      {clicado ? 'Clicado!' : 'Clique aqui'}
    </button>
  );
}
